import logging
import docker

log = logging.getLogger(__name__)
client = docker.from_env()


def list_containers():
    return client.containers.list()


def start_container(name: str):
    container = client.containers.get(name)
    container.start()


def check_health(container) -> str:
    """Return health status: 'healthy', 'unhealthy', 'no_healthcheck', or container status."""
    container.reload()
    if container.status != 'running':
        return container.status
    health = container.attrs.get('State', {}).get('Health')
    if health is None:
        return 'no_healthcheck'
    return health['Status']


def restart_unhealthy(labels: dict = None) -> list[str]:
    """Check all running containers and restart unhealthy ones. Returns list of restarted names."""
    filters = {'status': 'running'}
    if labels:
        filters['label'] = [f'{k}={v}' for k, v in labels.items()]
    containers = client.containers.list(filters=filters)
    restarted = []
    for c in containers:
        status = check_health(c)
        if status == 'unhealthy':
            log.warning('Restarting unhealthy container: %s', c.name)
            c.restart(timeout=10)
            restarted.append(c.name)
        elif status == 'exited':
            log.warning('Container exited unexpectedly: %s', c.name)
    return restarted
